import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Divider, Chip } from '@mui/material';
import response from './response.json';

interface GoldenHour {
  morningStart: string;
  morningEnd: string;
  eveningStart: string;
  eveningEnd: string;
}

interface SunriseSunsetData {
  location: string;
  sunrise: string;
  sunset: string;
  goldenHour: GoldenHour;
  dayLength: string;
}

export default function Widget() {
  const data = response.data as SunriseSunsetData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" fontWeight={600} sx={{ mb: 1, color: response.meta.primaryColor }}>
              Sunrise & Sunset
            </Typography>
            <Typography variant="body2" color="text.secondary">
              {data.location}
            </Typography>
          </Box>

          <Stack direction="row" spacing={2} alignItems="center">
            <Box>
              <Typography variant="caption" color="text.secondary">
                Sunrise
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {data.sunrise}
              </Typography>
            </Box>
            <Box>
              <Typography variant="caption" color="text.secondary">
                Sunset
              </Typography>
              <Typography variant="body2" fontWeight={500}>
                {data.sunset}
              </Typography>
            </Box>
          </Stack>

          <Divider sx={{ my: 1.5 }} />

          <Box>
            <Typography variant="caption" color="text.secondary">
              Day Length
            </Typography>
            <Typography variant="body2" fontWeight={500}>
              {data.dayLength}
            </Typography>
          </Box>

          <Divider sx={{ my: 1.5 }} />

          <Box>
            <Typography variant="caption" color="text.secondary" sx={{ mb: 0.5 }}>
              Golden Hours
            </Typography>
            <Stack direction="row" spacing={0.5}>
              <Chip label={`Morning: ${data.goldenHour.morningStart} - ${data.goldenHour.morningEnd}`} sx={{ fontSize: '11px', px: 1 }} />
              <Chip label={`Evening: ${data.goldenHour.eveningStart} - ${data.goldenHour.eveningEnd}`} sx={{ fontSize: '11px', px: 1 }} />
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
